class UndergroundSystem:

    def __init__(self):
        # Müşteri kimliğine göre giriş istasyonu ve zamanını saklar:
        # {customer_id: (start_station_name, start_time)}
        self.check_in_data = {} 

        # İstasyon çiftlerine göre toplam seyahat süresini ve sefer sayısını saklar:
        # {(start_station_name, end_station_name): [total_time, trip_count]}
        self.station_trip_aggregates = {}

    def checkIn(self, id: int, stationName: str, t: int) -> None:
        self.check_in_data[id] = (stationName, t)

    def checkOut(self, id: int, stationName: str, t: int) -> None:
        start_station, start_time = self.check_in_data.pop(id)

        route = (start_station, stationName)
        travel_time = t - start_time

        if route not in self.station_trip_aggregates:
            self.station_trip_aggregates[route] = [0, 0]

        self.station_trip_aggregates[route][0] += travel_time
        self.station_trip_aggregates[route][1] += 1

    def getAverageTime(self, startStation: str, endStation: str) -> float:
        route = (startStation, endStation)
        total_time, trip_count = self.station_trip_aggregates[route]
        return total_time / trip_count
